+    assert_eq!(json["blocks_count"].as_i64(), Some(0));
+    assert_eq!(json["mutes_count"].as_i64(), Some(0));
+    assert!(json["first_tweet_date"].is_string());
+    assert!(json["last_tweet_date"].is_string());
